class ExamRoom {
public:
    ExamRoom(int n) {
        n_ = n;
    }

    int seat() {
        if (students_.empty()) {
            return 0;
        }
        int maxDist = 0, res = 0;
        for (int i = 0; i < students_.size() - 1; i++) {
            int dist = students_[i + 1] - students_[i] - 1;
            if (dist > maxDist) {
                maxDist = dist;
                res = students_[i] + (dist / 2);
            }
        }
        if (students_.back() + 1 != n_) {
            int dist = students_.back() + 1 - students_.back();
            if (dist > maxDist) {
                maxDist = dist;
                res = students_.back() + 1;
            }
        }
        students_.push_back(res);
        return res;
    }

    void leave(int p) {
        students_.erase(std::remove(students_.begin(), students_.end(), p), students_.end());
    }
private:
    int n_;
    vector<int> students_;
};
```
